#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    // Read entire stdin into a buffer
    fseek(stdin, 0, SEEK_END);
    long len = ftell(stdin);
    fseek(stdin, 0, SEEK_SET);
    char *buf = (char*)malloc(len + 1);
    if (!buf) return 0;
    fread(buf, 1, len, stdin);
    buf[len] = '\0';
    // Replace literal "\\n" with a space so tokenisation works
    for (long i = 0; i + 1 < len; ) {
        if (buf[i] == '\\' && buf[i+1] == 'n') {
            memmove(buf + i + 1, buf + i + 2, len - (i + 2) + 1);
            buf[i] = ' ';
            len--;
        } else {
            i++;
        }
    }
    int T, choice;
    char *ptr = buf;
    int consumed = 0;
    if (sscanf(ptr, "%d%n", &T, &consumed) != 1) { free(buf); return 0; }
    ptr += consumed;
    for (int i = 0; i < T; ++i) {
        if (sscanf(ptr, "%d%n", &choice, &consumed) != 1) {
            printf("Invalid choice");
        } else {
            if (choice == 1) printf("Option 1 selected");
            else if (choice == 2) printf("Option 2 selected");
            else if (choice == 3) printf("Option 3 selected");
            else printf("Invalid choice");
        }
        if (i != T-1) printf("\n");
        // move pointer forward past the last integer (or whatever was attempted)
        if (sscanf(ptr, "%*d%n", &consumed) == 0) break;
        ptr += consumed;
    }
    free(buf);
    return 0;
}

