            input.replace(i, 2, " ");
        } else ++i;
    }
    stringstream ss(input);
    int T;
    if (!(ss >> T)) return 0;
    for (int i = 0; i < T; ++i) {
        int choice;
        if (!(ss >> choice)) {
            cout << "Invalid choice";
        } else if (choice == 1) {
            cout << "Option 1 selected";
        } else if (choice == 2) {
            cout << "Option 2 selected";
        } else if (choice == 3) {
            cout << "Option 3 selected";
        } else {
            cout << "Invalid choice";
        }
        if (i != T-1) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws IOException{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder all = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            all.append(line).append('\n');
        }
        // Replace literal "\\n" with a space so tokenisation works
        String data = all.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(data);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < T; i++) {
            if (!st.hasMoreTokens()) {
                out.append("Invalid choice");
            } else {
                int choice = Integer.parseInt(st.nextToken());
                switch (choice) {
                    case 1: out.append("Option 1 selected"); break;
                    case 2: out.append("Option 2 selected"); break;
                    case 3: out.append("Option 3 selected"); break;
                    default: out.append("Invalid choice");
                }
            }
            if (i != T-1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

